// React required process.env.NODE_ENV for early init decision-making
// This carries a much lighter footprint than a Node globals polyfill
(window as any).process = {env: {NODE_ENV: 'production'}};

import axios from 'axios';
import * as React from 'react';
import * as ReactBootstrap from 'react-bootstrap';
import * as ReactDOM from 'react-dom';

interface SkillsGridState {
    skills: any[];
    mode: string;
    version: string;
}

class SkillsGrid extends React.Component<any, SkillsGridState> {

    constructor(props) {
        super(props);
        this.state = {
            skills: [],
            mode: '',
            version: ''
        };
    }

    onListSkills() {
        axios.get(`http://${location.host}/version`)
        .then(res => this.setState({version: res.data.version}));
        axios.get(`http://${location.host}/skill/list`)
        .then(res => this.setState({skills: res.data.skills}));
    }

    onLaunch(record) {
        const command = JSON.stringify({command: record.name});
        axios.post(`http://${location.host}/launch-dev`, command)
        .then(() => this.onListSkills());
    }

    onStop(record) {
        const command = JSON.stringify({
            command: record.name
        });
        axios.post(`http://${location.host}/terminate`, command)
        .then(() => this.onListSkills());
    }

    launchConsole() {
        axios.post(`http://${location.host}/reset-proxy/9191`)
        .then(() => {
            axios.get(`http://${location.host}/devtools`)
            .then(res => {
                const frontEnd =
                    res.data[0].devtoolsFrontendUrl.replace(
                        '127.0.0.1',
                        location.hostname,
                    );
                window.open(
                    `http://${location.hostname}:9191${frontEnd}`,
                    'skills',
                );
            });
        });
    }

    launchSSMConsole() {
        axios.post(`http://${location.host}/reset-proxy/12345`)
        .then(() => {
            axios.get(`http://${location.host}/ssm-devtools`)
            .then(res => {
                const frontEnd =
                    res.data[0].devtoolsFrontendUrl.replace(
                        '127.0.0.1',
                        location.hostname,
                    );
                window.open(
                    `http://${location.hostname}:12345${frontEnd}`,
                    'ssm',
                );
            });
        });
    }

    componentDidMount() {
        //TODO: REMOVE DEPRECATION
        //We only care about the mode if we are running in electron
        axios.get(`http://${location.host}/mode`)
        .then(res =>
            this.setState({mode: res.data.electron ? res.data.mode : ''})
        );
        this.onListSkills();
    }

    render() {
        let skills = [];
        this.state.skills.forEach((record) => {
            if(!record.running) {
                skills.push(<ReactBootstrap.ListGroupItem>
                    <div className="row">
                        <div className="col-xs-6 col-sm-8 col-md-10">
                            <h4>{record.name} <small>v{record.version}</small></h4>
                        </div>
                        <div className="col-xs-6 col-sm-4 col-md-2">
                            <ReactBootstrap.Button bsStyle="success" className="btn-block" onClick={() => this.onLaunch(record)}>
                                <span className="glyphicon glyphicon-play"></span>&nbsp;
                                <span>Launch</span>
                            </ReactBootstrap.Button>
                        </div>
                    </div>
                </ReactBootstrap.ListGroupItem>);
            }
            else {
                skills.push(<ReactBootstrap.ListGroupItem>
                    <div className="row">
                        <div className="col-xs-6 col-sm-8 col-md-10">
                            <h4>{record.name} <small>v{record.version}</small></h4>
                        </div>
                        <div className="col-xs-6 col-sm-4 col-md-2">
                            <ReactBootstrap.ButtonGroup className="running">
                                <ReactBootstrap.Button bsStyle="danger" onClick={() => this.onStop(record)}>
                                    <span className="glyphicon glyphicon-stop"></span>&nbsp;
                                </ReactBootstrap.Button>
                                <ReactBootstrap.Button bsStyle="default" onClick={() => this.launchConsole()}>
                                    <span className="glyphicon glyphicon-cog"></span>&nbsp;
                                </ReactBootstrap.Button>
                            </ReactBootstrap.ButtonGroup>
                        </div>
                    </div>
                </ReactBootstrap.ListGroupItem>);
            }
        });
        return <div className="row">
            <div className="col-sm-12">
                <h1 className="pull-left" style={{marginBottom:20}}>Skills Manager <span className="version">v{this.state.version}</span></h1>
                <div className="pull-right" style={{paddingTop:20}}>
                    <ReactBootstrap.ButtonGroup>
                        <ReactBootstrap.Button bsStyle="default" onClick={() => this.onListSkills()}>
                            <span className="glyphicon glyphicon-refresh"></span>&nbsp;
                            <span>Refresh</span>
                        </ReactBootstrap.Button>
                        {
                        //TODO: REMOVE DEPRECATION
                        //The debug button is only relevant if we are running in Electron
                        }
                        {this.state.mode === 'int-developer' &&
                            <ReactBootstrap.Button bsStyle="default" onClick={() => this.launchSSMConsole()}>
                                <span className="glyphicon glyphicon-cog"></span>&nbsp;
                                <span>Debug</span>
                            </ReactBootstrap.Button>
                        }
                    </ReactBootstrap.ButtonGroup>
                </div>
                <div className="clearfix"></div>
                <ReactBootstrap.ListGroup>{skills}</ReactBootstrap.ListGroup>
            </div>
        </div>;
    }
}

document.addEventListener('DOMContentLoaded', () => {
    ReactDOM.render(<SkillsGrid/>, document.getElementById('grid'));
});
